const express = require('express');
const crypto = require('crypto');

const app = express();
const port = process.env.PORT || 3000;

// Middleware to parse JSON and keep the raw body for signature verification
app.use(express.json({
  verify: (req, res, buf) => {
    req.rawBody = buf;
  }
}));

app.post('/webhook', (req, res) => {
  const signature = req.headers['x-prembly-signature'];
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!signature) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // If there's no body, rawBody might be undefined
  const payload = req.rawBody ? req.rawBody : Buffer.from('');

  try {
    const hmac = crypto.createHmac('sha256', apiKey || '');
    hmac.update(payload);
    const computedSignature = hmac.digest('base64');

    if (crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(computedSignature))) {
      return res.status(200).json({ status: 'success' });
    } else {
      return res.status(401).json({ error: 'Invalid signature' });
    }
  } catch (err) {
    return res.status(401).json({ error: 'Invalid signature' });
  }
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

